+import {getPositions, MDAstTypes} from './mdast';
+import {yamlRegex} from './regex';
+
+type RuleSet = {
+  all: boolean,
+  disabled: Set<string>,
+  enabled: Set<string>,
+};
+
+type Marker = {
+  line: number,
+  action: 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines',
+  rules: string[] | null,
+  lineCount?: number,
+};
+
+type Range = {start: number, end: number};
+
+/**
+ * Applies a transform while preserving linter directive lines and the portions of
+ * the document disabled for one rule. Directives are intentionally parsed by
+ * line, rather than as generic comments, so lookalikes in Markdown content do
+ * not affect linting.
+ */
+export function applyScopedRuleIgnores(text: string, ruleAlias: string | null, aliases: string[], transform: (text: string) => string): string {
+  const ranges = getProtectedRanges(text, ruleAlias, aliases);
+  if (ranges.length === 0) {
+    return transform(text);
+  }
+
+  const replacements: string[] = [];
+  let protectedText = text;
+  for (let index = ranges.length - 1; index >= 0; index--) {
+    const range = ranges[index];
+    const placeholder = `{LINTER_DIRECTIVE_${index}_PLACEHOLDER}`;
+    replacements.unshift(text.substring(range.start, range.end));
+    protectedText = protectedText.substring(0, range.start) + placeholder + protectedText.substring(range.end);
+  }
+
+  protectedText = transform(protectedText);
+  for (let index = 0; index < replacements.length; index++) {
+    protectedText = protectedText.replace(new RegExp(`\\\\{LINTER_DIRECTIVE_${index}_PLACEHOLDER\\\\}`, 'i'), replacements[index].replace(/\\$/g, '$$$$'));
+  }
+
+  return protectedText;
+}
+
+function getProtectedRanges(text: string, ruleAlias: string | null, aliases: string[]): Range[] {
+  const lines = getLines(text);
+  const markers = getMarkers(text, lines, aliases);
+  const protectedLines = new Set<number>(markers.map((marker) => marker.line));
+  if (ruleAlias !== null) {
+    for (const line of getDisabledLines(markers, lines.length, ruleAlias)) {
+      protectedLines.add(line);
+    }
+  }
+
+  return mergeRanges([...protectedLines]
+      .sort((a, b) => a - b)
+      .map((line) => ({start: lines[line].start, end: lines[line].end})));
+}
+
+function getLines(text: string): Range[] {
+  const lines: Range[] = [];
+  let start = 0;
+  for (let index = 0; index <= text.length; index++) {
+    if (index === text.length || text[index] === '\
') {
+      lines.push({start, end: index});
+      start = index + 1;
+    }
+  }
+
+  return lines;
+}
+
+function getMarkers(text: string, lines: Range[], aliases: string[]): Marker[] {
+  const excludedRanges = getExcludedRanges(text);
+  const aliasesByLowercase = new Set(aliases.map((alias) => alias.toLowerCase()));
+  const markers: Marker[] = [];
+
+  lines.forEach((lineRange, line) => {
+    if (excludedRanges.some((range) => lineRange.start >= range.start && lineRange.end <= range.end)) {
+      return;
+    }
