+  const htmlMatch = lineText.match(/^[ \	]*<!--\\s*(linter-(?:disable-next-n-lines|disable-next-line|disable|enable)(?::\\s*[^\\s]+)?(?:[ \	]+.*?)?)\\s*-->[ \	]*$/i);
