+}
+
+function getDisabledLines(markers: Marker[], numberOfLines: number, ruleAlias: string): Set<number> {
+  const disabledLines = new Set<number>();
+  const scopes: RuleSet[] = [];
+  const normalizedAlias = ruleAlias.toLowerCase();
+
+  for (const marker of markers) {
+    if (marker.action === 'disable-next-line' || marker.action === 'disable-next-n-lines') {
+      const end = Math.min(numberOfLines - 1, marker.line + (marker.action === 'disable-next-line' ? 1 : marker.lineCount));
