+        if (marker.rules === null || marker.rules.includes(normalizedAlias)) {
+          disabledLines.add(line);
+        }
+      }
+      continue;
+    }
+
+    if (marker.action === 'disable') {
+      scopes.push({all: marker.rules === null, disabled: new Set(marker.rules ?? []), enabled: new Set()});
+      continue;
+    }
+
+    if (marker.rules === null) {
+      scopes.pop();
+    } else {
+      for (const rule of marker.rules) {
+        for (let index = scopes.length - 1; index >= 0; index--) {
+          const scope = scopes[index];
+          if (!scopeDisables(scope, rule)) {
+            continue;
+          }
