+    }
+  }
+
+  return disabledLines;
+}
+
+function closeRules(scopes: RuleSet[], rules: string[]): void {
+  for (const rule of rules) {
+    for (let index = scopes.length - 1; index >= 0; index--) {
+      const scope = scopes[index];
+      if (!scopeDisables(scope, rule)) {
+        continue;
+      }
+
+      if (scope.all) {
+        scope.enabled.add(rule);
+      } else {
+        scope.disabled.delete(rule);
+        if (scope.disabled.size === 0) {
+          scopes.splice(index, 1);
+        }
+      }
+      break;
+    }
+  }
+}
+
+function scopeDisables(scope: RuleSet, rule: string): boolean {
+  return scope.all ? !scope.enabled.has(rule) : scope.disabled.has(rule);
+}
+
+function mergeRanges(ranges: Range[]): Range[] {
+  return ranges.reduce((merged, range) => {
+    const previous = merged[merged.length - 1];
+    if (previous !== undefined && range.start <= previous.end + 1) {
+      previous.end = Math.max(previous.end, range.end);
+    } else {
+      merged.push({...range});
+    }
+    return merged;
+  }, [] as Range[]);
